// // This module compares two 3-bit numbers and outputs whether A is less than or equal to B, B is less than or equal to A, and if they are not equal.
module top_module(
  input [2:0] A,
  input [2:0] B,
  output a_greater,
  output b_greater,
  output equal
);assign a_greater = (A > B) ? 1'b1 : 1'b0;
  assign b_greater = (B > A) ? 1'b1 : 1'b0;
  assign equal = (A == B) ? 1'b1 : 1'b0;

endmodule
